function normalizeRefUri(v) {
  if (v == null) return null;
  if (typeof v === 'string') {
    const s = v.trim();
    if (!s) return null;
    if (/^https?:\/\//i.test(s) || /^did:[a-z0-9]+:/i.test(s) || /^urn:/i.test(s)) return s;
    return null;
  }
  if (typeof v === 'object') {
    if (v['@id']) return normalizeRefUri(v['@id']);
    if (v.href) return normalizeRefUri(v.href);
    if (v.id && typeof v.id === 'string') return normalizeRefUri(v.id);
    if (v.hasTarget) return normalizeRefUri(v.hasTarget);
    if (v.target) return normalizeRefUri(v.target);
  }
  return null;
}

function extractReferencesFromEntry(entry) {
  if (!entry || typeof entry !== 'object') return [];
  const refs = [];
  for (const field of REFERENCE_FIELDS) {
    const v = entry[field];
    if (v == null) continue;
    const arr = Array.isArray(v) ? v : [v];
    for (const item of arr) {
      const uri = normalizeRefUri(item);
      if (uri) refs.push({ field: field, uri: uri });
    }
  }
  if (Array.isArray(entry.links)) {
    for (const l of entry.links) {
      if (l && typeof l.href === 'string') {
        const uri = normalizeRefUri(l.href);
        if (uri) refs.push({ field: 'links', uri: uri, rel: l.rel || '' });
      }
    }
  }
  return refs;
}

function entryMatchesUri(entry, uri) {
  if (!entry || typeof entry !== 'object' || !uri) return false;
  const candidates = [
    entry['@id'], entry.id, entry.identifier, entry._id,
    entry.uri, entry.url, entry.did, entry.canonicalUri
  ].filter(Boolean).map(String);
  return candidates.indexOf(uri) !== -1;
}
