        const rootPath = cat.responseRootPath || '';
        const entries = cat.sourceData ? extractEntries(cat.sourceData, rootPath) : [];
        for (const entry of entries) {
            crawlIndex.push({
                entry,
                catName, catId,
                strategy: cat.strategy || 'none',
                idField: cat.responseAssetIdField || '',
                nameField: cat.responseAssetNameField || '',
                typeField: cat.responseAssetTypeField || '',
                typeMapping: Array.isArray(cat.typeMapping) ? cat.typeMapping : [],
                crawlOnly: cat._crawlOnly === true
            });
