    for (var li = 0; li < order.length; li++) { if (rawAreas.indexOf(order[li]) >= 0) labels.push(labelMap[order[li]]); }
    accessLabel = labels.join(" + ") || "No Access";
}

msg.payload = {
    response: {
        action: "hydrateSession",
        status: "success",
        user: {
            id: String(dcmUser._id || ""),
            username: dcmUser.username,
            email: dcmUser.email || "",
            status: dcmUser.status || "active",
            roles: dcmUser.roles || [],
            permissions: permissions,
            access: accessAreas,
            accessAreas: rawAreas,
            accessLabel: accessLabel,
            expiresAt: dcmUser.expiresAt || null
        }
    }
};
return msg;

