const now = new Date().toISOString();

// All permission areas and actions
const allAreas = [
    'harvest.run', 'harvest.scope', 'harvest.lifecycle', 'harvest.crawling',
    'schema.registry', 'catalogue.registry',
    'users', 'roles', 'audit'
];
const readActions = ['read'];
const crudActions = ['create', 'read', 'update', 'delete'];
const specialActions = { 'harvest.run': ['execute'], 'harvest.lifecycle': ['configure'], 'harvest.crawling': ['configure'] };

// Build editor permissions: every area's read, create, update; no delete; no users/roles write
const editorPerms = [];
for (const area of allAreas) {
    if (area === 'users' || area === 'roles') {
        editorPerms.push(area + '.read');
        continue;
    }
    if (specialActions[area]) {
        for (const a of specialActions[area]) editorPerms.push(area + '.' + a);
    } else {
        editorPerms.push(area + '.read', area + '.create', area + '.update');
    }
}
editorPerms.push('audit.read');

// Build viewer permissions: every area's read only
const viewerPerms = [];
for (const area of allAreas) {
    if (specialActions[area]) {
        // viewers can only read, not execute/configure
        viewerPerms.push(area + '.read');
    } else {
        viewerPerms.push(area + '.read');
    }
}

const roles = [
    { key: 'admin', name: 'Administrator', description: 'Full system access (wildcard)', permissions: ['*'], system: true },
    { key: 'editor', name: 'Editor', description: 'Can create and update in all areas, no delete, no user/role management', permissions: editorPerms, system: true },
    { key: 'viewer', name: 'Viewer', description: 'Read-only access to all areas', permissions: viewerPerms, system: true }
];

msg._rolesToSeed = roles;
msg._roleIdx = 0;

// Start with first role
const r = roles[0];
msg.collection = "dcm_roles";
msg.operation = "updateOne";
msg.payload = [
    { key: r.key },
    {
        $setOnInsert: {
            key: r.key,
            name: r.name,
            description: r.description,
            permissions: r.permissions,
            system: true,
            createdAt: now
        },
        $set: { updatedAt: now }
    },
    { upsert: true }
];
return msg;

const roles = msg._rolesToSeed || [];
let idx = (msg._roleIdx || 0) + 1;
msg._roleIdx = idx;

if (idx >= roles.length) {
    node.status({ fill: 'green', shape: 'dot', text: 'Seeded admin + ' + roles.length + ' roles' });
    return null; // done
}

const r = roles[idx];
const now = new Date().toISOString();
msg.collection = "dcm_roles";
msg.operation = "updateOne";
msg.payload = [
    { key: r.key },
    {
        $setOnInsert: {
            key: r.key,
            name: r.name,
            description: r.description,
            permissions: r.permissions,
            system: true,
            createdAt: now
        },
        $set: { updatedAt: now }
    },
    { upsert: true }
];
return msg;

// Write login.success audit entry
var resp = msg.payload && msg.payload.response ? msg.payload.response : msg.payload;
msg._savedLoginResponse = msg.payload;
msg.collection = "dcm_audit_log";
msg.operation = "insertOne";
msg.payload = {
  timestamp: new Date().toISOString(),
  action: "login.success",
  actor: resp.user ? resp.user.username : (msg._sessionUsername || "unknown"),
  target: resp.user ? resp.user.username : (msg._sessionUsername || "unknown"),
  area: "auth",
  result: "ok"
};
return msg;

msg._savedLoginResponse = msg.payload;
msg.collection = "dcm_audit_log";
